import { Component,Input,OnInit } from '@angular/core';
import { BuyerInfo, GiftsWithBuyers } from '../../Models/Sales';
import { SalesService } from '../../Services/SaleService';
import { DialogModule } from 'primeng/dialog';
import { CommonModule } from '@angular/common';
import {  Output, EventEmitter, OnChanges, SimpleChanges } from '@angular/core';


@Component({
  selector: 'app-gift-buyers-detail-comp',
  standalone: true,
  imports: [DialogModule,CommonModule],
  templateUrl: './gift-buyers-detail-comp.html',
  styleUrl: './gift-buyers-detail-comp.scss',
})
export class GiftBuyersDetailComp implements OnInit {
  @Input() giftId!: number;
  @Input() giftName!: string;
  @Input() displayDialog: boolean = false;  
@Output() displayDialogChange = new EventEmitter<boolean>();

  buyers: BuyerInfo[] = [];
  // giftName: string = '';
  isLoading: boolean = false;

  constructor(private salesService: SalesService) {}
  ngOnInit(): void {
    console.log('Gift ID:', this.giftId);
    if (this.giftId) {
      this.loadBuyers();
    }
  }
  loadBuyers() {
    this.isLoading = true;
    this.salesService.getGiftWithBuyers().subscribe((data: GiftsWithBuyers[]) => {
      const gift = data.find(g => g.giftId === this.giftId);
      if (gift) {
        this.buyers = gift.buyers;
        this.giftName = gift.giftName;
      }
      this.isLoading = false;
    }, err => {
      console.error('Error loading buyers', err);
      this.isLoading = false;
    });
  }

closeDialog() {
  this.displayDialog = false;
  this.displayDialogChange.emit(this.displayDialog);
}
}
<p>gift-buyers-detail-comp works!</p>

<p-dialog [(visible)]="displayDialog" [modal]="true" [header]="'רוכשים עבור: ' + giftName" [closable]="true" [style]="{width: '500px'}">
  <ng-container *ngIf="isLoading">
    <p>טוען רוכשים...</p>
  </ng-container>

  <table *ngIf="!isLoading && buyers.length > 0" class="table">
    <thead>
      <tr>
        <th>שם מלא</th>
        <th>אימייל</th>
        <th>כרטיסים שנקנו</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let buyer of buyers">
        <td>{{buyer.firstName}} {{buyer.lastName}}</td>
        <td>{{buyer.email}}</td>
        <td>{{buyer.ticketsPurchased}}</td>
      </tr>
    </tbody>
  </table>

  <p *ngIf="!isLoading && buyers.length === 0">אין רוכשים למתנה זו</p>
</p-dialog>
